/**
 * BxGrid 페이지네이션 및 BxGrid 를 렌더링 하는 내부 함수.
 *
 * @memberOf BxGrid
 *
 * @returns {BxGrid}
 * @private
 */
function _render(){

    let $container = this.$container,
        options = this[OPTS];

    options.loadComplete = (data) =>{
        // enablePaging: true -> 페이지네이션
        // enablePaging: false -> 무한스크롤

        data.action = this.action;

        this.onLoadComplete.call(this, data);

        if (data.rows.length === 0 && data.page !== 1){
            window.setTimeout(() =>{
                this.goPage(data.page - 1);
            }, 0);
            return;
        }

        // 전체, 현재 페이지, rownum.
        this.enablePaging && _initPage.call(this, data.records, data.page, this[OPTS].rowNum);

        if (data.userdata) delete data.userdata;
        // setting Param about Total Page
        this.setGridParam({total: data.total});
        // 사용자 reloadcomplete call
        this.onReloadComplete.call(this, data);

        _initFooter.call(this, this.footers);

        _initMacScrollBorder.call(this);

    };

    options.ondblClickRow = (id, dataIndex, colIndex, e) =>{

        let isEditable = _isEditable.call(this, id);

        if (isEditable){
            return;
        }

        let o = this.getRowData(id);

        this.onDblClick.call(this, o, e);
    };

    options.onSelectRow = (id, isSelect, e) =>{

        // multiSelect: false 인 경우, 오른쪽 버튼 누를 경우 call 되는 문제때문에 아래와 같이 처리
        // editCol 의 icon 클릭 시, e 가 undefined 가 들어오므로 이에 대한 처리도 같이한다.
        // if (_.isUndefined(e)) return;
        // if (!_.isEqual(e.type, 'click')) return;
        // console.log('selected!!!!!');

        if (options.multiselect && _isSelectedAllRow.call(this)){
            $('#cb_jqg1')[0].checked = true;
        }

        let isEditable = _isEditable.call(this, id);

        if (isEditable){
            return;
        }

        let o = this.getRowData(id);

        this.onSelectRow.call(this, o, e);
    };

    options.onCellSelect = (rowId, index, content, e) =>{

        let modelIdx = index;

        if (options.rownumbers) --modelIdx;
        if (options.multiselect) --modelIdx;

        let rowData = this.getRowData(rowId);
        let colName = null;

        if (modelIdx > 0) colName = options.colModel[modelIdx].name;
        else if ($(e.target).hasClass('jqgrid-rownum')) colName = 'rowNumbers';
        else colName = 'multiSelect';

        this.onSelectCell.apply(this, [index, content, rowData, colName, e]);

    };


    options.onSortCol = (sortName, colIdx, sortOrder) =>{

        let optionName = AJAX_OPTION.READ_OPTION;

        if (_isAjaxTransaction.call(this)){

            // 초기화
            _setAjaxSortList.call(this, sortName, sortOrder);

            let params = _getRequestParams.call(this, optionName);

            _transactionCRUD.call(this, optionName, params).then((data)=>{

                _setResponseDataToGridParam.call(this, data, false);

            });

            return false;
        }
        else {
            // onSortCol 이 불리기 전, page 가 1로 초기화되는 문제로 인해 해당 부분 추가.
            $container.setGridParam({page: this.movePage});
            return true;
        }
    };

    this.clearChangedData();

    // $.fn.fmatter.rowactions 내부에서 사용되기 위한 함수.
    this.inlineFunc = {

        edit(id, condition){

            let o = _getDataById.call(this, id);
            this.editRow(id);

            this.onInlineEdit.call(this, id, o);
            this.onRowAction.call(this, id, o, condition);

        },
        delete(id, condition){

            let o = _getDataById.call(this, id);

            this.delRowData(id);

            this.onInlineDelete.call(this, id, o);
            this.onRowAction.call(this, id, o, condition);
        },
        save(id, condition){


            if (_isAjaxTransaction.call(this)){

                this.saveRow(id).then(() =>{
                    _save.call(this);
                });
            }
            else {

                this.saveRow(id);

                _save.call(this);
            }

            /*
             * ajax 사용 시, inlineSave 및 rowAction callback 의 인자값의 차이로 아래와 같이 내부 함수를 만들어 사용
             * ajax 사용하는 경우 _getDataById 를 통해 해당 데이터를 구할때
             * 해당 값이 변경이전의 값을 갖고 있어 promise 를 통한 지연을 통해 아래 함수를 실행한다.
             * 이때, colModel 의 key 값을 변경해 해당 값을 가져오려 하였으나, _getDataById, _getLastId 등 내부 함수에서
             * id 컬럼을 사용하기 때문에 id 를 통한 값으로 데이터를 구하는 경우 추가적인 side effect 이 발생할 우려가 있어
             * 우선적으로 colModel 에 key 값 할당에 대한 부분을 doc 에서 제외하였으며,
             * 이 후 추가적으로 작업이 들어가야 한다.
             * */
            function _save(){

                let o = _getDataById.call(this, id);

                this.onInlineSave.call(this, id, o, !this.editFail);

                this.onRowAction.call(this, id, o, condition);
            }
        },
        cancel(id, condition){

            this.cancelRow(id);

            let o = _getDataById.call(this, id);

            this.onInlineCancel.call(this, id, o);
            this.onRowAction.call(this, id, o, condition);
        }
    };

    // 초기 랜더링시 각 action button(수정/삭제)에 바인딩된 이벤트 핸들러인 $.fn.fmatter.rowactions 메서드를 override 하여, 해당 이벤트를 가로챈다.

    // ** 각 버튼 엘리먼트에는 아래와 같은 방식으로 inline event 가 바인딩 되어있다.(this === btn 엘리먼트) **

    /*
     <div id="btn" ... onclick="return jQuery.fn.fmatter.rowactions.call(this, event, 'edit');" ....>
     */

    // 하지만 전역 메서드(rowactions) 내부 self 변수가 참조하는 this 값은, 항상 마지막으로 초기화된 this 값을 참조하게된다(동일 페이지에서 여러개의 컴포넌트를 생성했을 경우)
    // 즉 self 변수를 사용해도, 메서드 내부에서 개별 인스턴스 값을 가질 수 없는 상황이며, 이를 해결해기위해, 초기 $container 엘리먼트의
    // 내부 프로퍼티로 할당한 __this__ 프로퍼티를 사용한다.

    // 수정, 삭제 event

    // 함수 객체가 매번 재 할당된다.
    $.fn.fmatter.rowactions = function (e, condition){

        let $elem = $(this);

        let id = $elem.attr('id').replace(/^\D+_/g, '');

        let componentClassName = BXUI.Base.getComponentClassName('grid');

        // $container 엘리먼트
        let $container = $elem.parents(`.${componentClassName}`);

        // $container 엘리먼트에 할당시킨, 현재 this 값
        let self = $container.get(0).__this__;
        let o = _getDataById.call(self, id);

        if (_.isFunction(self.onBeforeRowAction)) {
            self.onBeforeRowAction.call(self, id, o, condition, execute);
        }
        else {
            execute();
        }

        function execute() {

            self.isInlineEdit = true;

            if (OPTS.multiselect) self.$container.setSelection(id);

            self.inlineFunc[condition].call(self, id, condition);
        }

    };

    // jqGrid 확장 소스....
    // errMassage 는 colModel Index를 전송 >> colModel.editrules 를 설정할때 사용가능
    $.extend($.jgrid, {

        info_dialog: (err = '', errMessage = '', c_b = '', modalopt = {}) =>{
            // editing 제외한 곳에서 다이얼로그 안뜨게 만들어줌.
            if (!parseInt(errMessage)) return;

            let idx = errMessage;
            let col = this[OPTS].colModel[idx];

            this.editFail = true;

            if (_.isUndefined(col.message)) return; // message가 지정 되지 않을 경우 사용자가 팝업을 직접 생성

            let message = col.message;

            $().bxDialog({
                style: 'stick',
                width: 400,
                confirmText: '확인',
                closeText: '취소',
                dimStyle: {
                    color: 'black',
                    enableBlur: false
                }
            }).alert({
                title: '유효성 검사 실패',
                content: message,
                onConfirm: function (e){
                    this.hide();
                }
            });
        },
        fixScrollOffsetAndhBoxPadding: () => {
            let self = this, grid = self.grid;

            if (!grid){
                return;
            }

            let p = self.p, bDiv = grid.bDiv,
                fixhBox = function (hDiv){
                    let $hDivhBox = $(hDiv).children("div").first();
                    $hDivhBox.css($hDivhBox.hasClass("ui-jqgrid-hbox-rtl") ? "padding-left" : "padding-right", p.scrollOffset);
                    hDiv.scrollLeft = bDiv.scrollLeft;
                };

            if ($(bDiv).width() > 0){
                p.scrollOffset = (bDiv.offsetWidth - bDiv.clientWidth) - 3; // can be 0 if no scrollbar exist
                // TODO: add detection of the width of vertical scroll bar if the grid is hidden
                // at the moment of executing fixScrollOffsetAndhBoxPadding (for example inside of inactive jQuery UI Tab)
                // one need just create close construction with visible:hidden style, add to body and get its width
                fixhBox(grid.hDiv);
                if (grid.sDiv){
                    fixhBox(grid.sDiv);
                }
            }
        }
    });

    _setCellAttr(this[OPTS].colModel);

    _renderJqGrid.call(this, () => {

        let {onRender, $pageContainer, groupHeaders, width, resizable} = this;

        $container.jqGrid(this[OPTS]);

        onRender.call(this);

        _addIconWrapper.call(this);

        _addImportExcel.call(this);

        _addExportButton.call(this);

        _setGroupHeaders.call(this, groupHeaders);

        _removeScopeAttr.call(this, this.$root);

        _setAccessibility.call(this);

        // set resize about grid table.
        if (resizable)  _addResizeListenerAtWindow.call(this);

        if (!options.shrinkToFit) _setHorizonScroll.call(this, width);

        if (_.isNull(width)) width = this.$container.width();

        this.setGridWidth(width);

    });

    return this;
}
