/**
 * 해당 아이디를 갖는 데이터를 반환한다.
 *
 * @param {string} id - 검색할 id
 *
 * @returns {object} id로 검색된 데이터
 *
 * @private
 * @memberOf BxGrid
 */
function _getDataById(id = ''){

    let o = {},
        items = this[OPTS].data,
        rowNum = items.length,
        prefix = id.replace(/\d+$/, ''),
        num = parseInt(id.replace(/\D+/, ''));

    for (let i in items){
        // ajax 시, reload 를 통해 rowId 달라지는 문제로 인해서 아래 prefix 및 rowNum 다시 구하는 부분을 추가함.
        // 추후 진행시, 다시 작업되야 합니다. [ key 값 달라지는 경우, 파생되는 문제들 전부 해결 ]
        if (_.isEqual(String(items[i].id), id) || _.isEqual(String(items[i].id), `${prefix}${num + rowNum}`)){
            // console.log(items[i]);
            o = items[i];
            delete o.format;
            break;
        }
    }

    return o;
}

/**
 * changedData 동기화를 위한 내부 함수
 *
 * @param {string} id - id 값
 * @param {string} condition - 변경될 상태 값
 * @param {object} preData - 이전 데이터
 * @private
 * @memberOf BxGrid
 */
function _changedDataSync(id = '', condition = '', preData = {}){

    let changedObj = this.changedObj;
    let insertIdx = changedObj.id.insert.indexOf(id);
    let updateIdx = changedObj.id.update.indexOf(id);
    let deleteIdx = changedObj.id.delete.indexOf(id);

    let data = _getDataById.call(this, id);

    switch (condition){
        case 'insert':
            if (deleteIdx !== -1 && _.isEqual(data, changedObj.data.delete[deleteIdx])){
                changedObj.id.delete.splice(deleteIdx, 1);
                changedObj.data.delete.splice(deleteIdx, 1);
            }

            changedObj.id.insert.push(id);
            changedObj.data.insert.push(data);

            break;

        case 'update':

            if (_.isEqual(data, preData)){
                return;
            }

            if (insertIdx === -1){

                if (updateIdx === -1){
                    changedObj.id.update.push(id);
                    changedObj.data.update.push(data);
                }
                else{
                    changedObj.data.update[updateIdx] = data;
                }
            }
            else{
                changedObj.data.insert[insertIdx] = data;
            }

            break;

        case 'delete':

            if (insertIdx !== -1){
                changedObj.id.insert.splice(insertIdx, 1);
                changedObj.data.insert.splice(insertIdx, 1);
            }
            else {

                if (updateIdx !== -1){
                    changedObj.id.update.splice(updateIdx, 1);
                    changedObj.data.update.splice(updateIdx, 1);
                }

                changedObj.id.delete.push(id);
                changedObj.data.delete.push(data);
            }

            break;

        default:
            break;
    }
}

/**
 * colModel 확장에 대한 랩핑 함수
 *
 * @param {object} inlineEditColOption - 인라인 edit컬럼 설정 옵션
 *
 * @private
 * @memberOf BxGrid
 */
function _expandColModel(inlineEditColOption = {}){

    // colModel 검사 및 key 값의 유무를 확인 및 keyColumn 셋팅.
    _validateColModel.call(this);
    // colModel editable 추가 및 확장
    _rowEditCustomizing.call(this);
    // editColModel 있는 경우 추가한다
    _addInlineBtnColumn.call(this, inlineEditColOption);
    // formatOption 추가 및 확장
    _expandFormatter.call(this);

}

/**
 * colModel 유효성 검사 및 key 값 설정 (id field 는 jqGrid 내부 id 를 사용을 원칙으로 한다.)
 *
 * @returns {string} key 로 설정된 컬럼의 name 속성
 *
 * @private
 * @memberOf BxGrid
 */
function _validateColModel(){

    let colModel = this[OPTS].colModel;
    let existKey = false;

    colModel.map((data) =>{
        if (!data.name){
            CONSOLE.prop.throw(BxGrid, 'colModel 내부 name', 'value');
        }

        if (data.name === 'id'){
            data.key = true;
            existKey = true;

            return;
        }
    });


    if (!existKey){
        // colModel 추가.
        let idCol = {
            name: 'id',
            hidden: true,
            key: true
        };
        colModel.splice(0, 0, idCol);
        existKey = true;
    }
}

/**
 * inline Eidt Mode 시, 엘리먼트와 유효성검사 커스터마이징 함수
 *
 * @private
 * @memberOf BxGrid
 */
function _rowEditCustomizing(){

    let colModel = this[OPTS].colModel;

    colModel.map((data, i) =>{

        let { editOption, name: colName, label: colLabel } = data;

        if (editOption){

            if (!_.isObject(editOption)){
                CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption', 'type');
            }

            let editType = editOption.type;
            let offerEditTypeArr = ['select', 'checkbox', 'radio', 'text', 'textarea', 'custom'];

            if (!_.isString(editType)){
                CONSOLE.prop.throw(BxGrid, colName + ' 의 editType', 'type');
            }

            if (_.isEqual(editType.trim(), '')){
                CONSOLE.prop.throw(BxGrid, colName + ' 의 editType', 'value');
            }

            if (offerEditTypeArr.indexOf(editType) === -1){
                CONSOLE.prop.throw(BxGrid, colName + ' 의 editType', 'value');
            }

            let { attr: editAttr, items: editItems, separator: editSeparator }= editOption;

            data.editable = true;
            data.edittype = 'custom';

            if (_.isEqual(editType, 'custom')){

                if (!_.isFunction(editOption.customElement)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 customElement', 'type');
                }

                if (!_.isFunction(editOption.customElementValue)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 customElementValue', 'type');
                }

                if (!_.isUndefined(editAttr)){
                    CONSOLE.prop.warn(BxGrid, colName + ' 의 editAttr 는 사용할 수 없습니다.', 'empty');
                }

                if (!_.isUndefined(editItems)){
                    CONSOLE.prop.warn(BxGrid, colName + ' 의 editItems 는 사용할 수 없습니다.', 'empty');
                }

                if (!_.isUndefined(editSeparator)){
                    CONSOLE.prop.warn(BxGrid, colName + ' 의 editOption.separator 는 사용할 수 없습니다.', 'empty');
                }

                data.editoptions = {
                    custom_element: editOption.customElement,
                    custom_value: editOption.customElementValue
                };
            }
            else{

                let havingItem = ['select', 'checkbox', 'radio'].indexOf(editType) !== -1;
                let editTargetCol = editOption.targetCol;

                // select, checkbox, radio 버튼 일 경우 items에 대한 type, value check..
                if (havingItem && !_.isArray(editItems)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editoption.items', 'type');
                }
                if (havingItem && (!_.isPlainObject(editItems[0]) || _.isEmpty(editItems[0]))){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editoption.items', 'value');
                }

                if (!havingItem && !_.isUndefined(editItems)){
                    CONSOLE.prop.warn(BxGrid, colName + ' 의 editItems 는 사용할 수 없습니다.', 'empty');
                }
                if (!_.isEqual(editType, 'checkbox') && !_.isUndefined(editSeparator)){
                    CONSOLE.prop.warn(BxGrid, colName + ' 의 ' + editType + ' 타입은 editOption.separator 는 사용할 수 없습니다.', 'empty');
                }

                // editAttr 값이 들어온 경우 attr에 대한 type, value check
                if (!_.isUndefined(editAttr) && !_.isPlainObject(editAttr)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption.attr', 'type');
                }
                if (!_.isUndefined(editAttr) && _.isEmpty(editAttr)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption.attr', 'value');
                }

                if (!_.isUndefined(editSeparator) && !_.isString(editSeparator)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption.separator', 'type');
                }

                data.editoptions = _createEditOptions.call(this, colName, colLabel, editType, editAttr, editItems, editSeparator, editTargetCol);

            }

            let validateOption = editOption.validateOption;
            // validation이 있는 경우만 추가 한다.
            if (validateOption){

                let validator = validateOption.validator;
                let message = validateOption.message;

                if (!_.isFunction(validator)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption.validateOption.validator', 'type');
                }

                // @deprecated
                if (!_.isUndefined(message) && !_.isString(message)){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption.validateOption.message', 'type');
                }

                // @deprecated
                if (!_.isUndefined(message) && _.isEqual(message.trim(), '')){
                    CONSOLE.prop.throw(BxGrid, colName + ' 의 editOption.validateOption.message', 'value');
                }

                if (!_.isUndefined(message)){
                    data.message = message;
                }

                data.editrules = {
                    custom: true,
                    custom_func: (data, colName, i) =>{

                        // i 는 colModel.map 의 인자값.
                        const $container = this.$container;
                        const id = $container.getGridParam('selrow');
                        const rowData = $container.getRowData(id);

                        const editOptions = $container.get(0).p.colModel[i].editOption;
                        const type = editOptions.type;
                        const items = editOptions.items;

                        const getFindValue = value => {

                            let findValue = _.find(items, {label: value});

                            return _.isUndefined(findValue) ? '' : findValue.value;
                        };

                        if (type === 'checkbox'){

                            const separator = editOptions.separator;

                            let divValue = data.split(separator);
                            let result = [];

                            _.forEach(divValue, v => result.push(getFindValue(v)));

                            data = result.join(separator);
                        }
                        else if (type === 'select' || type === 'radio'){
                            data = getFindValue(data);
                        }

                        let validateFail = validator.call(this, data, colName, rowData);

                        return [validateFail, i];
                    }
                };

            }

            //delete data.editOption;
        }
    });
}
/**
 * edit mode 변경시, 사용할 Element 지정 함수
 *
 * @param {string} colName - 컬럼 명
 * @param {string} colLabel - 컬럼 라벨
 * @param {string} editType - edit 타입
 * @param {string} editAttr - edit 속성
 * @param {array} editItems - edit 아이템
 * @param {string} editSeparator - edit 분리 기호
 * @param {string} editTargetCol - edit 할 타겟 컬럼 명
 *
 * @private
 * @memberOf BxGrid
 */
function _createEditOptions(colName, colLabel, editType, editAttr, editItems, editSeparator, editTargetCol){

    let self = this;

    let o = {
        //TODO 접근성 custom_element
        custom_element: function (cellValue, colData){

            let elem = [],
                rowId = colData.rowId,
                editAttrStr = editAttr ? _addEditElementAttr(colName, editAttr) : '';

            switch (editType){

                case 'text':

                    elem.push(`<input type="text" data-id="${rowId}" title="${colLabel}" value="${cellValue}" `);
                    elem.push(editAttrStr);
                    elem.push('/>');

                    break;

                case 'textarea':

                    elem.push(`<textarea title="${colLabel}" data-id=${rowId}`);
                    elem.push(editAttrStr);
                    elem.push('>' + cellValue + '</textarea>');

                    break;

                case 'checkbox':

                    editSeparator = editSeparator ? editSeparator : ', ';

                    let valueArr = cellValue.split(editSeparator);
                    elem.push('<div ');
                    elem.push(editAttrStr);
                    elem.push('>');

                    for (let i in editItems){

                        let editItem = editItems[i],
                            label = editItem.label,
                            value = editItem.value;

                        elem.push('<label class="edit_label">');

                        if (_.isUndefined(label)){
                            CONSOLE.prop.warn(BxGrid, colName + ' 의 editItem.label', 'value');
                        }

                        if (editTargetCol){

                            if (!_.isString(editTargetCol)){
                                CONSOLE.prop.warn(BxGrid, colName + ' 의 editOption.targetCol', 'type');
                            }

                            if (_.isUndefined(value)){
                                CONSOLE.prop.warn(BxGrid, colName + ' 의 editItem.value', 'value');
                            }

                            elem.push(`<input title="${label}" name="check_${rowId}" type="checkbox" value="${value}" data-id="${rowId}_${i}" `);
                        }
                        else{
                            elem.push(`<input title="${label}" name="check_${rowId}" type="checkbox" value="${label}" data-id="${rowId}_${i}" `);
                        }

                        elem.push(valueArr.indexOf(label) === -1 ? '' : 'checked');

                        elem.push(' />');

                        elem.push(label + '</label>');
                    }

                    elem.push('</div>');

                    break;

                case 'radio':
                    elem.push('<div ');
                    elem.push(editAttrStr);
                    elem.push('>');

                    for (let i  in editItems){

                        let editItem = editItems[i],
                            label = editItem.label,
                            value = editItem.value;

                        if (_.isUndefined(label)){
                            CONSOLE.prop.warn(BxGrid, colName + ' 의 editItem.label', 'value');
                        }

                        elem.push('<label class="edit_label">');

                        if (editTargetCol){

                            if (!_.isString(editTargetCol)){
                                CONSOLE.prop.warn(BxGrid, colName + ' 의 editOption.targetCol', 'type');
                            }

                            if (_.isUndefined(value)){
                                CONSOLE.prop.warn(BxGrid, colName + ' 의 editItem.value', 'value');
                            }

                            elem.push(`<input title="${label}" name="radio_${rowId}" type="radio" value="${value}" data-id="${rowId}_${i}"`);
                        }
                        else{
                            elem.push(`<input title="${label}" name="radio_${rowId}" type="radio" value="${value}" data-id="${rowId}_${i}"`);
                        }

                        elem.push(_.isEqual(label, cellValue) ? 'checked' : '');

                        elem.push(' />');
                        elem.push(label + '</label>');
                    }

                    elem.push('</div>');
                    break;

                case 'select':
                    elem.push('<div ');
                    elem.push(editAttrStr);
                    elem.push('>');

                    elem.push(`<select title="${colLabel}" data-id="${rowId}">`);
                    for (let i in editItems){

                        let editItem = editItems[i],
                            label = editItem.label,
                            value = editItem.value;

                        if (_.isUndefined(label)){
                            CONSOLE.prop.warn(BxGrid, colName + ' 의 editItem.label', 'value');
                        }

                        // targetCol 프로퍼티가 존재할경우
                        if (editTargetCol){

                            if (!_.isString(editTargetCol)){
                                CONSOLE.prop.warn(BxGrid, colName + ' 의 editOption.targetCol', 'type');
                            }

                            if (_.isUndefined(value)){
                                CONSOLE.prop.warn(BxGrid, colName + ' 의 editItem.value', 'value');
                            }

                            elem.push(`<option value="${value}" ${label === cellValue ? 'selected' : ''}>`);
                        }
                        else{
                            elem.push(`<option value="${value}" ${label === cellValue ? 'selected' : ''}>`);
                        }

                        elem.push(label + '</option>');
                    }

                    elem.push('</select>');
                    elem.push('</div>');

                    break;

                default :
                    break;
            }
            return elem.join('');
        },
        custom_value: function ($elem){

            let text = '';
            let value = '';

            switch (editType){

                case 'text':

                    text = $elem.val();

                    break;

                case 'textarea':

                    text = $elem.val();

                    break;

                case 'checkbox':

                    editSeparator = editSeparator ? editSeparator : ',';

                    let length = $elem.parent().find('input:checked').length;

                    if (length){

                        let i = 0;
                        let $checkbox = null;
                        let $label = null;

                        for (i = 0; i < length - 1; i++){

                            $checkbox = $($elem.parent().find('input:checked').get(i));
                            $label = $checkbox.parent();

                            text += $label.text() + editSeparator;

                            if (editTargetCol) value += $checkbox.val() + editSeparator;
                        }


                        $checkbox = $($elem.parent().find('input:checked').get(i));
                        $label = $checkbox.parent();

                        text += $label.text();

                        if (editTargetCol){
                            value += $checkbox.val();
                            self.targetColModelValues[editTargetCol] = value;
                        }
                    }
                    else {
                        self.targetColModelValues[editTargetCol] = '';
                    }

                    break;

                case 'radio':

                    let $radio = $elem.parent().find('input:checked');
                    let $label = $radio.parent();

                    text = $label.text();

                    if (editTargetCol){
                        value = $radio.val();
                        self.targetColModelValues[editTargetCol] = value;
                    }

                    break;

                case 'select':

                    $elem = $elem.find('select option:selected');

                    text = $elem.text();

                    if (editTargetCol){
                        value = $elem.val();
                        self.targetColModelValues[editTargetCol] = value;
                    }

                    break;
            }

            return text;
        }
    };

    return o;
}

/**
 * inline Edit Mode 의 Element 속성 부여 함수
 * @param {string} colName - 컬럼 명
 * @param {string} editAttr - edit 속성
 *
 * @returns {string} 추가된 element
 *
 * @private
 * @memberOf BxGrid
 */
function _addEditElementAttr(colName = '', editAttr = ''){

    let elem = [];
    let excludeAttr = ['data-id', 'id'];

    for (let name in editAttr){

        if (excludeAttr.indexOf(name) !== -1){
            CONSOLE.prop.warn(BxGrid, colName + ' 의 editoption.attr 의 ' + name + '속성은 사용할 수 없습니다.', 'empty');
            continue;
        }

        elem.push(name + '="' + editAttr[name] + '" ');
    }
    return elem.join('');
}

