/**
 * colModel 에 inlineBtn 컬럼 추가 함수
 * @private
 * @memberOf BxGrid
 */
function _addInlineBtnColumn(inlineEditColOption){

    if (inlineEditColOption.inlineEditCol){

        let inlineEditColModel = inlineEditColOption.inlineEditColModel;
        let editColWidth = Object.keys(inlineEditColModel).length * 25;
        let editable = inlineEditColModel['edit'] === undefined ? false : true;

        const iconSet = {
            edit: 'fa-pencil',
            delete: 'fa-trash-o',
            save: 'i-save',
            cancel: 'i-undo'
        };

        let editBtnCol = {
            // label: inLineEditColLable,
            // name: 'format',
            // width: 100,
            // sortable: false,
            // editable: true,
            // formatter: 'actions',
            // edittype: 'custom',
            // editoptions: {
            //     custom_element: function(dummy, obj){
            //         let test = [];
            //         test.push('<div class="fommater ui-jqgrid-actions">')
            //         test.push('<div class="ui-corner-all ui-pg-div ui-inline-save" id="jEditButton_' + obj.rowId + '" onclick="return $.fn.fmatter.rowactions.call(this,event,\'save\');" onmouseover="$(this).addClass(\'ui-state-hover\');" onmouseout="$(this).removeClass(\'ui-state-hover\');">');
            //         test.push('<i class="bw-icon i-25 i-save"></i>');
            //         test.push('</div>');
            //         test.push('<div class="ui-corner-all ui-pg-div ui-inline-cancel" id="jDeleteButton_' + obj.rowId + '"onclick="return $.fn.fmatter.rowactions.call(this, event, \'cancel\')" onmouseover="$(this).addClass(\'ui-state-hover\');" onmouseout="$(this).removeClass(\'ui-state-hover\');">');
            //         test.push('<i class="bw-icon i-25 i-undo"></i>');
            //         test.push('</div>');
            //         test.push('</div>')
            //         return test.join('');
            //     },
            //     custom_value: function(elem){
            //         return '';
            //     }
            // },
            // align: 'center'
            label: inlineEditColOption.inlineEditColLabel,
            name: 'format',
            width: editColWidth,
            align: "center",
            editable: editable,
            sortable: false,
            formatter: function (cellvalue, options, rowObject){
                let rowId = options.rowId;
                let html = createBtnElement(rowId, 'show');
                return html;
            }
        };

        let createBtnElement = function (rowId, prop){

            let btnTemplate = [];

            btnTemplate.push('<div class="ui-corner-all ui-pg-div ui-inline-{state}"');
            btnTemplate.push(' id="j{state}Button_{rowId}" onclick="return $.fn.fmatter.rowactions.call(this,event, \'{state}\');"');
            btnTemplate.push(' onmouseover="$(this).addClass(\'ui-state-hover\');" onmouseout="$(this).removeClass(\'ui-state-hover\');">');
            btnTemplate.push('<button type="button" class="bw-icon i-25 {iconSet}" title="{iconStr}"><span class="blind">{iconStr}</span></button>');
            btnTemplate.push('</div>');

            btnTemplate = btnTemplate.join('');

            let html = [];

            html.push('<div class="fommater ui-jqgrid-actions">');

            for (let key in inlineEditColModel){

                if (!inlineEditColModel[key][prop]) continue;

                html.push(btnTemplate.replace(/\{state}/g, key)
                    .replace(/\{rowId}/, rowId)
                    .replace(/\{iconSet}/, iconSet[key])
                    .replace(/\{iconStr}/g, ALT_TEXT[iconSet[key]]));
            }

            html.push('</div>');

            return html.join('');
        };

        if (editable){

            editBtnCol.edittype = 'custom';

            editBtnCol.editoptions = {
                custom_element: function (dummy, obj){
                    let test = createBtnElement(obj.rowId, 'showEditMode');
                    return test;
                },
                custom_value: function (elem){
                    return '';
                }
            };
        }

        this[OPTS].colModel.push(editBtnCol);

    }
}

/**
 * formatter 기능 설정 및 커스터마이징 함수
 *
 * @private
 * @memberOf BxGrid
 */
function _expandFormatter(){

    let colModel = this[OPTS].colModel;

    colModel.forEach((data, i) =>{

        if (_.isPlainObject(data.formatOption)){

            let name = data.name;
            let item = data.formatOption;
            let options = item.options || {};
            let type = item.type;


            if (!_.isString(type) || _.isUndefined(FORMAT_TYPE[type.toUpperCase()])){
                CONSOLE.prop.throw(BxGrid, 'formatter type', 'type');
            }

            if (type === FORMAT_TYPE.CUSTOM && (!_.isFunction(item.customFormatter) || !_.isFunction(item.customUnFormatter))){
                CONSOLE.prop.throw(BxGrid, `colModel ${name}의 formatter type이 custom인 경우 customFormatter와 customUnformatter 함수가 반드시 필요합니다.`, 'empty');
            }

            if (type === FORMAT_TYPE.DATE && (
                    !_.isString(options.dataFormat) || !_.isString(options.viewFormat) ||
                    options.dataFormat.length === 0 ||
                    options.viewFormat.length === 0
                )
            ){
                CONSOLE.prop.throw(BxGrid, `colModel ${name}의 formatter type이 date인 경우 dataFormat 값과 viewFormat 값이 반드시 필요합니다.`, 'empty');
            }

            if (type === FORMAT_TYPE.CURRENCY && !_.isUndefined(options.decimalPlaces)){

                if (!_.isNumber(options.decimalPlaces)){
                    CONSOLE.prop.throw(BxGrid, 'decimalPlaces', 'type');
                }

                if (options.decimalPlaces < 0){
                    CONSOLE.prop.throw(BxGrid, `colModel ${name}의 formatOption.options.decimalPlaces 값은 양수만 입력 가능합니다`, 'empty');
                }

                if (_.toString(options.decimalPlaces).indexOf('.') > -1){
                    CONSOLE.prop.throw(BxGrid, `colModel ${name}의 formatOption.options.decimalPlaces는 정수만 입력 가능합니다`, 'empty');
                }
            }

            let maxDecimalPlaces = 30;

            switch (type){

                case FORMAT_TYPE.CURRENCY:
                    let tempOptions = {};

                    if (!_.isUndefined(options.prefix)) tempOptions.prefix = options.prefix;
                    if (!_.isUndefined(options.suffix)) tempOptions.suffix = options.suffix;

                    if (!_.isUndefined(options.decimalPlaces)){
                        tempOptions.decimalPlaces = options.decimalPlaces > maxDecimalPlaces ? maxDecimalPlaces : options.decimalPlaces;
                    }

                    tempOptions.thousandsSeparator = ',';
                    tempOptions.defaultValue = '';

                    data.formatter = type;
                    data.formatoptions = tempOptions;

                    break;
                case FORMAT_TYPE.DATE:
                case FORMAT_TYPE.TEL:
                case FORMAT_TYPE.PID:
                case FORMAT_TYPE.BZNO:
                case FORMAT_TYPE.CARD:
                case FORMAT_TYPE.CUSTOM:
                    data.formatter = _customFormatter.bind(this, item);
                    data.unformat = _customUnFormatter.bind(this, item);
                    break;
            }

        }
    });
}

/**
 * type별 formatter 기능 설정
 *
 * @private
 * @memberOf BxGrid
 */
function _customFormatter(formatOptions, cellvalue, options, rowObject){

    let result = '';
    let type = formatOptions.type;
    let option = formatOptions.options;
    let separator = option && option.separator ? option.separator : '-';
    let params = {separator: separator};

    // 커스텀 formatter는 사용자에게 입력받은 함수로 fomatting
    if (type === FORMAT_TYPE.CUSTOM){
        result = formatOptions.customFormatter(cellvalue, options, rowObject);
    }
    else {

        if (type === FORMAT_TYPE.DATE){
            params.dataFormat = option.dataFormat;
            params.viewFormat = option.viewFormat;
        }

        result = UTIL.getFormatString(type, cellvalue, params);

        if (type === FORMAT_TYPE.CARD){
            result = result.value;
        }
    }

    return result;
}

/**
 * type별 unformatter 기능 설정
 *
 * @private
 * @memberOf BxGrid
 */
function _customUnFormatter(formatOptions, cellvalue, options){

    let result = '',
        type = formatOptions.type,
        option = formatOptions.options;

    // 커스텀 unformatter는 사용자에게 입력받은 함수로 unfomatting
    if (type === FORMAT_TYPE.CUSTOM){
        result = formatOptions.customUnFormatter(cellvalue, options);
    }
    else{
        result = UTIL.getUnFormatString(type, cellvalue, option);
    }

    return result;
}

/**
 * BxGrid 페이지네이션 구현을 위한 내부 메서드
 *
 * @param {int} records - 총 데이터 수
 * @param {int} currentPage -
 * @param {int} rowNum - 사용자가 입력한 페이지 당 최대 행 수.
 *
 * @memberOf BxGrid
 * @private
 */
//그리드 페이징  
function _initPage(records = 0, currentPage = 0, rowNum = 0){

    let self = this;

    // 전체 페이지 사이즈
    let totalPageSize = Math.ceil(records / rowNum); // 총 페이지

    // 페이지 그룹 사이즈
    let pageGroupSize = this.pageGroupSize;

    // 전체 페이지 그룹
    let totalPageGroupSize = Math.ceil(totalPageSize / pageGroupSize);  // 총 페이지 / 페이지 목록 갯수 --> 뿌려줄 데이터 

    // 현재 페이지 그룹
    let currentPageGroup = Math.ceil(currentPage / pageGroupSize);    // 현재 페이지가 총 페이지 리스트 중 몇번째 인지

    // 페이지 리스트가 1보다 작으면 1로 초기화    
    // 페이지 리스트가 총 페이지 리스트보다 커지면 총 페이지 리스트로 설정    
    if (currentPage < 1) currentPage = 1;
    if (currentPageGroup > totalPageGroupSize) currentPageGroup = totalPageGroupSize;

    // 시작 페이지    
    // 끝 페이지    
    let startPageGroup = ((currentPageGroup - 1) * pageGroupSize) + 1;
    let endPageGroup = (startPageGroup + pageGroupSize) - 1;

    // 시작 페이지와 끝페이지가 1보다 작으면 1로 설정    
    // 끝 페이지가 마지막 페이지보다 클 경우 마지막 페이지값으로 설정    
    if (startPageGroup < 1) startPageGroup = 1;

    if (endPageGroup > totalPageSize) endPageGroup = totalPageSize;
    if (endPageGroup < 1) endPageGroup = 1;

    // 현재 페이지 컨테이너 초기화
    this.$pageContainer.html('');

    let className = BxGrid.className;

    let $pagingContainer = $(`<div class="bx-ui-${className} bw-paging add-mg-t"></div>`);

    if (currentPageGroup > 1){

        let $prevBtnGroup = $('<div class="ctr-btn"></div>');

        let $first = _createPagingNavElement('forward', e => this.goPage(1));
        let $prev = _createPagingNavElement('pre', e => this.goPage(startPageGroup - 1));

        $prevBtnGroup.append($first);
        $prevBtnGroup.append($prev);

        $pagingContainer.append($prevBtnGroup);
    }

    let $pagingGroup = $('<div class="paging-btn"></div>');

    for (let i = startPageGroup; i <= endPageGroup; i++){

        let $a = null;

        if (i === Number(currentPage)){
            $a = $('<button type="button" class="btn-paging on" title =' + i + '>' + i + '</button>');
        }
        else{
            $a = $('<button type="button" class="btn-paging" title =' + i + '>' + i + '</button>');
            $a.on('click', (e) => this.goPage(i));
        }

        $pagingGroup.append($a);
    }

    $pagingContainer.append($pagingGroup);

    if (currentPageGroup < totalPageGroupSize){

        let $nextCtrBtn = $('<div class="ctr-btn"></div>');

        let $next = _createPagingNavElement('next', e => this.goPage(endPageGroup + 1));
        let $last = _createPagingNavElement('backward', e => this.goPage(totalPageSize));

        $nextCtrBtn.append($next);
        $nextCtrBtn.append($last);

        $pagingContainer.append($nextCtrBtn);
    }

    this.$pageContainer.append($pagingContainer);
}

/**
 * BxGrid 페이지 네비게이션 엘리먼트 생성 함수
 *
 * @param {string} directionClass - 방향에 대한 클래스
 * @param {function} clickEvent - 버튼 클릭 이벤트
 *
 * @returns {string} element
 *
 * @memberOf BxGrid
 * @private
 */
function _createPagingNavElement(directionClass = '', clickEvent = function (){
}){

    let element = `<button type="button" class="btn-paging" title="{title}"><i class="bw-bx-icon i-15 i-ctrl-${directionClass}"><span class="blind">{altText}</span></i></button>`;

    let $innerHtml = $(element.replace(/\{title}/, ALT_TEXT[directionClass])
        .replace(/\{altText}/, ALT_TEXT[directionClass]));

    $innerHtml.on('click', clickEvent);

    return $innerHtml;
}

/**
 * Ajax Method별 URL & 파라미터 객체 생성 함수
 *
 * @param {string} mType - 총 데이터 수
 * @param {string} url - 요청 보낼 URL
 * @param {object} params - 요청 보낼 파라미터
 *
 * @memberOf BxGrid
 * @private
 */
function _getUrlObjectToMethod(mType = '', url = '', params = {}){

    let result = {};

    if (!RESTFUL_METHOD[mType.toUpperCase()]){
        CONSOLE.prop.throw(BxGrid, 'Transaction Method', 'value');
    }

    switch (mType.toLowerCase()){
        case 'get':

            let tempUrl = _.cloneDeep(url);
            let invoke = "";

            if (tempUrl.indexOf('?') > -1){
                params = _mergeURLToQueryString(tempUrl, params);
                tempUrl = tempUrl.slice(0, tempUrl.indexOf('?'));
            }

            invoke = UTIL.objectToQueryString(params);
            tempUrl = invoke.length === 0 ? tempUrl : tempUrl + '?' + invoke;

            result.url = tempUrl;

            break;

        case 'put':
        case 'delete':
        case 'post':

            result.url = url;
            result.params = params;

            break;
    }

    return result;
}

/**
 * URL의 querystring과 params를 합쳐주는 함수
 *
 * @param {string} url - URL 데이터
 * @param {object} params - 파라미터
 *
 * @returns {object} - 합쳐진 parameter object
 *
 * @memberOf BxGrid
 * @private
 */
function _mergeURLToQueryString(url = '', params = {}){
    let queryObject = UTIL.queryStringToObject(url);

    _.assign(queryObject, params);

    return queryObject;
}

/**
 * 파라메터 생성 함수.
 *
 * @param {string} [optionName = ''] - optionName
 * @param {object} [extendParams = {}] - extendParams
 *
 * @returns {object} params - parameter object
 *
 * @private
 *
 * @memberOf BxGrid
 */
function _getRequestParams(optionName = '', extendParams = {}){

    const ajaxModel = _getAjaxModel.call(this, optionName);
    const reqModel = ajaxModel.reqModel;

    const ajaxOption = _getAjaxOption.call(this, optionName);
    const method = ajaxOption.method.toLowerCase();

    let params = {};

    if (method !== 'get' && !_.isEmpty(reqModel)){
        _.set(params, reqModel, {});
    }

    if (optionName === AJAX_OPTION.READ_OPTION){

        const pagingModel = DEFAULT_REQ_PARAMS_MODEL.paging;

        if (this.enablePaging){

            _.assign(_.get(params, reqModel, params), {
                [pagingModel.currentPage]: this.movePage > 0 ? this.movePage : 1,
                [pagingModel.pageSize]: this[OPTS].rowNum
            });
        }

        // 정렬 관련 parameter 확장
        $.extend(true, params, _getRequestSortParams.call(this));

        extendParams = _.size(ajaxModel.extendParams) ? ajaxModel.extendParams : extendParams;

        $.extend(true, params, extendParams);
    }
    else{
        $.extend(true, _.get(params, reqModel, params), extendParams);
    }


    return params;
}

/**
 * sort 파라메터 생성 함수.
 *
 *
 * @returns {object} params - parameter object
 *
 * @private
 *
 * @memberOf BxGrid
 */
function _getRequestSortParams(){

	const ajaxModel = this.ajaxModel;
    const reqModel = _getTransModel.call(this).reqModel;
    const method = ajaxModel[AJAX_OPTION.READ_OPTION].method.toLowerCase();

    let params = {};

    if (_.isString(reqModel) && method !== 'get'){
        _.set(params, reqModel, {});
    }

    const sortList = ajaxModel.ajaxSortList;
    const sortModel = DEFAULT_REQ_PARAMS_MODEL.sort;

    if (!_.isEmpty(sortList.columns)){

        _.assign(_.get(params, reqModel, params), {
            [sortModel.columns]: sortList.columns.join(','),
            [sortModel.orderBy]: sortList.orderBy.join(',')
        });
    }

    return params;
}

/**
 * ajaxSortList 초기 설정 함수
 * @param sortName - BxGrid 초기 sortName
 * @param sortOrder - BxGrid 초기 sortOrder
 *
 * @private
 * @memberOf BxGrid
 */
function _setAjaxSortList(sortName = '', sortOrder = ''){

    let ajaxModel = this.ajaxModel;

    ajaxModel.ajaxSortList = {
        columns: [],
        orderBy: []
    };

    if (_.isEmpty(sortName)) return;

    sortName += ' ' + sortOrder;

    let sortColArr = sortName.split(', ');

    for (let idx in sortColArr){

        let sortColDetailInfo = sortColArr[idx].split(' ');

        if (sortColDetailInfo.length !== 2) continue;

        ajaxModel.ajaxSortList.columns.push(sortColDetailInfo[0]);
        ajaxModel.ajaxSortList.orderBy.push(sortColDetailInfo[1]);
    }
}



/**
 * Ajax 통신을 이용해 반환받은 response Data 를 Grid 속성으로 변경하는 함수
 * @param {object} [data={}] 서버 response data
 * @param {boolean} [isBeforeRender=false] 그리드가 렌더링 되기 전인지 여부
 * @private
 * @memberOf BxGrid
 */
function _setResponseDataToGridParam(data = {}, isBeforeRender = false){

    let opts = this[OPTS];
    let resModel = _getTransModel.call(this).resModel;

    // 전달받은 데이터의 items 가져온다.(resModel.items 기준)
	let items = _.get(data, resModel.items);

	// 전달받은 데이터의 totalCount 가져온다.(resModel.totalCount 기준)
	let totalCount = _.get(data, resModel.totalCount);

    if (!_.isArray(items)){
        CONSOLE.prop.throw(BxGrid, ERR_MSG.notFoundItemViaResModel);
    }

    if (!TYPE.isNumber(totalCount)){
        CONSOLE.prop.throw(BxGrid, ERR_MSG.notFoundTotalCountViaResModel);
    }

    _.assign(data, {
        page: this.movePage ? this.movePage : 1,
        rows: items,
        records: totalCount,
        total: Math.ceil(totalCount / Math.abs(opts.rowNum))
    });

    let params = {
        datastr: data,
        datatype: opts.datatype
    };

    delete data[resModel.items.split('.')[0]];
    delete data[resModel.totalCount.split('.')[0]];

    if (isBeforeRender){
        _.assign(opts, params);
    }
    else{
        this.setGridParam(params);
    }
}

/**
 * 웹 접근성 적용
 * @private
 * @memberOf BxGrid
 */
function _setAccessibility(){

    _initCaption.call(this);//헤더 영역에 캡션 추가

    _theadCustomizing.call(this);// Top, middle 테이블의 Thead 커스텀
}

/**
 * caption을 생성 한다.
 * @private
 * @memberOf BxGrid
 */
function _initCaption(){

    let $tableElem = this.$root.find('table');

    _.map($tableElem, elem =>{

        if ($(elem).hasClass('ui-jqgrid-htable') && $(elem).find('.ui-jqgrid-htable > caption').length === 0){

            let columns = '';
            let flag = false;

            this[OPTS].colModel.map((data, i) =>{

                if (data.label !== undefined){

                    if (flag){
                        columns += ', ';
                    }

                    flag = true;

                    this.groupHeaders.map((groupHeader) =>{

                        if (data.name === groupHeader.startColName){
                            columns += _getSubCaption.call(this, groupHeader);
                        }

                    });

                    columns += data.label;
                }
            });

            let caption = ALT_TEXT['caption'].replace(/\{columns}/g, columns);

            $(elem).prepend('<caption class="blind">' + caption + '</caption>');
        }
    });

}

/**
 * 헤더 테이블 Thead를 바디 테이블에 동일하게 적용
 * @private
 * @memberOf BxGrid
 */
function _theadCustomizing(){

    const headerTableClass = '.ui-jqgrid-htable';
    const bodyTableBody = '.ui-jqgrid-btable tbody';

    let $root = this.$root;

    let $htable = $root.find(headerTableClass);
    let $caption = $htable.find('caption');

    let _$htable = $htable.clone();

    let $thead = _$htable.find('thead');

    let _$caption = _$htable.find('caption');

    let $th = $htable.find('thead th');
    let $tbody = $root.find(bodyTableBody);


    //리더기가 읽는거 방지
    $th.attr('aria-hidden', true);
    $caption.attr('aria-hidden', true);

    _$htable.find('button').remove();
    _$htable.find('input').remove();

    if (!UTIL.isIE9()) {

        //복사된 헤더 숨김
        $thead.addClass('blind');
    }
    else {

        // ie9일때 blind로 처리하면 body가 사라진다.
        // header에서 적용된 blind css가 body 까지 영향을 미치는듯 하다.
        _$caption.removeClass('blind');
        _$caption.css('display', 'none');

        $thead.css('display', 'none');
    }

    $tbody.before(_$caption.get(0)).before($thead.get(0));
}

/**
 * sub caption을 반환한다.
 *
 * @param {object} groupHeader 객체
 * @returns {string} subColumns - groupHeader에서 caption으로 들어갈 내용
 * @private
 */
function _getSubCaption(groupHeader = {}){

    let subColumns = '';
    let trTags = groupHeader.content;

    $.parseHTML(trTags).map((trTag) => {

        let thTags = $(trTag).html();

        $.parseHTML(thTags).map((thTag) => {
            subColumns += $(thTag).text() + ', ';
        });

    });

    return subColumns;
}

/**
 * inline Edit mode 상태 데이터 반환 함수
 *
 * @param id - rowid
 * @returns {object} o - inline Edit Mode 데이터 객체
 * @private
 */
function _getEditData(id = ''){

    let $container = this.$container,
        colModel = this[OPTS].colModel,
        $tdArr = $container.find(`tr#${id} td:not(.td_cbox):not(.jqgrid-rownum)`),
        checkElement = ['checkbox', 'radio'],
        o = {};

    if (!_.isString(id)){
        CONSOLE.prop.throw(BxGrid, 'id', 'type');
    }

    if (_.isEmpty(id)){
        CONSOLE.prop.throw(BxGrid, 'id', 'value');
    }

    for (let i = 0; i < $tdArr.length; i++){

        let $td = $($tdArr[i]),
            $editableArr = $td.children().length === 0 ? [] : $($td.find('span.editable'));

        if ($editableArr.length === 0) continue;

        let name = colModel[i].name,
            $elemArr = $($editableArr).find(`input[type=text],input[type=radio], input[type=checkbox], select, textarea`),
            data = {};

        for (let j = 0; j < $elemArr.length; j++){

            let elem = $elemArr[j],
                $elem = $(elem),
                k = $elem.attr('data-id'),
                _o = {};

            if (checkElement.indexOf(elem.type) !== -1){
                let _k = $elem.val();
                _o[k] = {};
                _.assign(_o[k], {
                    [_k]: elem.checked
                });
            }
            else{
                _o[k] = $elem.val();
            }

            _.assign(data, _o);

        }

        o[name] = data;

    }
    return o;
}

/**
 * grid param 내부에 paging 및 sort 모델 있는지 유무 반환 함수
 * @param {string}[k ='']
 * @returns {boolean}
 * @private
 */
function _isContainBasicGridParam(k = ''){

    let pagingModel = DEFAULT_REQ_PARAMS_MODEL.paging,
        sortModel = DEFAULT_REQ_PARAMS_MODEL.sort,
        result = false;

    if (_.isEqual(pagingModel.currentPage, k) || _.isEqual(pagingModel.pageSize, k)
        || _.isEqual(sortModel.columns, k) || _.isEqual(sortModel.orderBy, k)){

        result = true;
    }

    return result;
}

/**
 * 그리드의 병합 함수
 *
 * @param {array} [groupHeader = [] - 병합을 할 헤더 리스트
 * @returns {object} 생성된 인스턴스
 * @private
 */
function _setGroupHeaders(groupHeader = []){

    if (_.isEmpty(groupHeader)) return;

    let $root = this.$root,
        o = [],
        tableClass = 'bx-grid-group-header';

    // remove col resizeable
    $root.find('span.ui-jqgrid-resize').remove();

    groupHeader.map((item, i) =>{

        let html = [],
            {startColName, numberOfCol, content} = item;

        if (!_.isPlainObject(item)){
            CONSOLE.prop.throw(BxGrid, `groupOption[${i}]`, 'type');
        }

        if (!_.isString(startColName)){
            CONSOLE.prop.throw(BxGrid, `groupOption[${i}].startColName`, 'type');
        }

        if (!_.isInteger(numberOfCol)){
            CONSOLE.prop.throw(BxGrid, `groupOption[${i}].numberOfCol`, 'type');
        }

        if (!_.isString(content)){
            CONSOLE.prop.throw(BxGrid, `groupOption[${i}].content`, 'type');
        }

        html.push(`<table class="${tableClass}">`);
        html.push(`<caption class="blind">그룹 헤더 목록</caption>`);
        html.push(`<thead>`);
        html.push(content);
        html.push(`</thead>`);
        html.push('</table>');

        o.push({
            startColumnName: startColName,
            numberOfColumns: numberOfCol,
            titleText: html.join('')
        });
    });

    if (!_.isEmpty(o)){
        this.$container.setGroupHeaders({
            useColSpanStyle: true,
            groupHeaders: o
        });
    }

    let $thArr = $root.find('th:has(table)');

    for (let i = 0; i < $thArr.length; i++){
        $($thArr[i]).attr('title', '');
    }
}

/**
 * scope 속성을 삭제하는 함수
 *
 * @param {object} $container - scope속성을 삭제할 jqeury element
 * @private
 */
function _removeScopeAttr($container = $(document.documentElement)){

    if (_.isEmpty(this.groupHeaders)) return;

    if (!_.isElement($container.get(0))){
        CONSOLE.prop.throw(BxGrid, '$container', 'type');
    }

    $container.find('[scope]').removeAttr('scope');

}

/**
 * colModel에 cellattr을 설정하는 함수
 * http://www.trirand.com/jqgridwiki/doku.php?id=wiki:colmodel_options
 *
 * @param {array} colModels - colModels 객체 배열
 * @private
 */
function _setCellAttr(colModels = []){

    if (!_.isArray(colModels)){
        CONSOLE.prop.throw(BxGrid, 'colModels', 'type');
    }

    colModels.forEach((cm) =>{

        if (!cm.attr) return;

        if (!_.isFunction(cm.attr)){
            CONSOLE.prop.throw(BxGrid, 'colModel.attr', 'type');
        }

        cm.cellattr = function (rowId, val, rowObj, colModel, rData){

            let attr = cm.attr(rowId, val, colModel, rData);

            if (!_.isPlainObject(attr)){
                CONSOLE.prop.throw(BxGrid, 'colModel.attr의 리턴', 'type');
            }

            // console.log(cm.name, colModel);

            return UTIL.objectToStringAttr(attr);

        };

    });

}

/**
 * row를 선택 / 해제 하는 함수
 *
 * @param {string|array} id - row id
 * @param {type} type - 선택 타입 (select / clear)
 * @private
 */
function _setSelection(id = '', type = 'select'){

    if (!_.isString(id) && !_.isArray(id)){
        CONSOLE.prop.throw(BxGrid, 'id', 'type');
    }

    if (!_.isString(type)){
        CONSOLE.prop.throw(BxGrid, 'type', 'type');
    }

    const $container = this.$container;
    id = _.isArray(id) ? id : [id];

    _.forEach(id, (_id) =>{

        if (!_.isString(_id)){
            CONSOLE.prop.throw(BxGrid, 'id', 'type');
        }

        const isSelected = _.indexOf(this.getSelectedId(), _id) !== -1;
        const selectable = type === 'select' ? !isSelected : isSelected;

        if (selectable) $container.setSelection(_id);

    });

}
/**
 * GroupHeader 의 마지막 th border 제거 함수
 * @param {{}} [$headerSubWrapper=null] $headerSubWrapper 'div.ui-jqgrid-hbox'
 * @private
 * @memberOf BxGrid
 */
function _removeGroupHeaderLastThBorder({ $headerSubWrapper = null } = {}){

    if (_.isNull($headerSubWrapper)){
        CONSOLE.prop.throw(BxGrid, '$headerContainer', 'value');
    }

    let { groupHeaders } = this,
        hasGroupHeader = !_.isEmpty(groupHeaders);

    const APPLY_STYLE = 'border-right: 0px !important',
        ORIGIN_HEADER_LAST_TH_CLASS = hasGroupHeader ?
            'thead > tr.jqg-second-row-header > th:visible:last' : 'thead > tr.ui-jqgrid-labels > th:visible:last',
        GROUP_HEADER_LAST_TH_CLASS = 'thead > tr.jqg-third-row-header > th:visible:last';


    let { $elem: $originLastTh, style } = _getLastTh(ORIGIN_HEADER_LAST_TH_CLASS);

    if (hasGroupHeader && $originLastTh.get(0).rowSpan === 1){
        let { $elem: $groupHeaderLastTh, style } = _getLastTh(GROUP_HEADER_LAST_TH_CLASS);

        $groupHeaderLastTh.attr('style', style + APPLY_STYLE);
    }

    $originLastTh.attr('style', style + APPLY_STYLE);

    function _getLastTh(rowClass = ''){

        let $lastTh = $headerSubWrapper.find(rowClass),
            style = $lastTh.attr('style') || '';

        return {
            $elem: $lastTh,
            style
        };
    }
}

/**
 * footers의 값을 통해 footer들을 생성 및 유효성 검사를 한다.
 * @param {array} footers - footers를 구성하는 정보
 * @private
 * @memberOf BxGrid
 */
function _initFooter(footers){

    if (_.isNull(footers))  return;

    let content = '';

    function _addRowFooter(footer, rowNum){
        footer.map(data => {

            if (!_.isString(data.type)){
                CONSOLE.prop.throw(BxGrid, 'footers.type', 'type');
            }
            if (!_.isString(data.colName)){
                CONSOLE.prop.throw(BxGrid, 'footers.colName', 'type');
            }

            if (!_.isString(data.content)){
                CONSOLE.prop.throw(BxGrid, 'footers.content', 'type');
            }
            if (!_.isInteger(data.numberOfCol)){
                CONSOLE.prop.throw(BxGrid, 'footers.numberOfCol', 'type');
            }

            let params = {
                [data.colName]: JSON.stringify(data.content)
            };

            switch (data.type){
                case 'count':
                case 'avg':
                case 'sum':
                case 'min':
                case 'max':
                    content = this.$container.jqGrid("getCol", data.colName, false, data.type);

                    params[data.colName] = content;

                    _addFooterData.call(this, 'set', params, data, rowNum);
                    break;
                case 'label':
                    _addFooterData.call(this, 'set', params, data, rowNum);
                    break;
                default:
                    CONSOLE.prop.throw(BxGrid, 'footers.type', 'type');
            }
        });
    }

    for (let i = 0; i < footers.length; i++){
        _addRowFooter.call(this, footers[i], i);
    }

}

/**
 * 맥 OS 일 경우 스크롤영역에 보더를 추가
 * @private
 * @memberOf BxGrid
 */
function _initMacScrollBorder(){

    if (!$.browser.mac) return;

    const LAST_TD_CLASS = 'tr.ui-row-ltr > td:last-child',
        MAC_SCROLL_CLASS = 'mac-scroll';

    let $container = this.$container;

    $container.find(LAST_TD_CLASS).addClass(MAC_SCROLL_CLASS);
}

/**
 * 해당 열에 footer 추가 또는 해당 열이 이미 있을 경우 업데이트를 한다
 * @param {string} action = 'set' - set or get, 값을 가져 오거나 업데이트
 * @param {string} data = '' - td 영역을 구성 하는 정보
 * @param {object} footer = {} - footer를 구성하는 전체 정보
 * @param {int} rowCount = 0 - 열 번호
 * @private
 * @memberOf BxGrid
 */
function _addFooterData(action = 'set', data = '', footer = {}, rowCount = 0){

    let success = false, res = {}, numberOfCol = footer.numberOfCol, format = true;

    function isEmpty(obj){
        var i;
        for (i in obj){
            if (obj.hasOwnProperty(i)){
                return false;
            }
        }
        return true;
    }

    if (action === undefined){
        action = "get";
    }

    if (typeof format !== "boolean"){
        format = true;
    }

    action = action.toLowerCase();

    this.$container.each(function (){ // jqgrid에서 footer customizing

        let t = this, p = t.p, vl, $td, nm, iCol;

        if (!t.grid || !p.footerrow){
            return false;
        }
        if (action === "set" && isEmpty(data)){
            return false;
        }

        success = true;

        let ftable = $(t.grid.sDiv)
            .find(".ui-jqgrid-hbox>.ui-jqgrid-ftable")[0];

        if (ftable === null || ftable.rows === null){
            return false;
        }

        if (!t.firstRow){

            t.firstRow = $(ftable.rows[0]).clone(true); // 첫 번째 row는 jqgrid가 자체 생성 해주어서 복사 해놓고 재활용

            let html = $(t.grid.bDiv).find('.jqgfirstrow').clone(true); // bodyTable에 있는 jqgfirstrow(fot auto resize) 복사

            $(ftable).find('tbody').prepend(html);
        }

        rowCount += 1;

        if (rowCount > 1){

            if (ftable.rows[rowCount] === undefined){

                $(ftable).find('tbody').append(t.firstRow.clone(true));
            }
        }

        let cells = ftable.rows[rowCount].cells,
            fcells = t.grid.fsDiv === undefined ? {} : t.grid.fsDiv.children(".ui-jqgrid-ftable")[0].rows[rowCount].cells;

        for (nm in data){
            iCol = p.iColByName[nm];
            if (data.hasOwnProperty(nm) && iCol !== undefined){
                if (action === "get"){
                    res[nm] = $(cells[iCol]).html();
                }
                else if (action === "set"){

                    if (footer.type === 'label' || footer.type === 'count'){
                        vl = data[nm];
                    }
                    else {
                        vl = t.formatter("", data[nm], iCol, data, "edit");
                    }

                    let content = footer.content.split('{0}');
                    let temp = '';

                    for (let i = 0; i < content.length; i++){
                        if (i !== 0) temp += vl;
                        temp += content[i];
                    }

                    vl = temp;

                    if (numberOfCol > 1 && $(cells[iCol]).css("display") !== 'none'){

                        for (let i = 1; i < numberOfCol; i++){

                            if (i === 1){
                                $(cells[iCol]).attr("colSpan", numberOfCol);
                            }

                            $(cells[iCol + i]).hide();
                        }

                    }

                    $td = $(cells[iCol]).add(fcells[iCol]);

                    $td.html(vl);

                    // if (p.colModel[iCol].attr) { // 추후 attr 필요할때 열어줌
                    //     $td.attr({ "title": stripHtml(vl) });
                    // }
                }
            }
        }

    });

    return action === "get" ? res : success;
}

/**
 * BxGrid 리사이즈시 footer의 td 간격을 재 조정 한다
 * @private
 * @memberOf BxGrid
 */
function _resizeFooter(){

    if (!this[OPTS].userDataOnFooter) return;

    this.$container.each(function (){

        let t = this, p = t.p;
        let colModel = p.colModel;
        let footTable = $(t.grid.sDiv)
            .find(".ui-jqgrid-hbox>.ui-jqgrid-ftable tr.jqgfirstrow").first()[0].cells;

        colModel.map((data, i) =>{
            footTable[i].style.width = data.width + "px";
        });
    });
}

