/**
 * grid에 excel export 버튼을 추가한다
 *
 * @private
 */
function _addExportButton(){

	if (!this.exportModel.enableExpButton) return;

    let $root = this.$root;
    let type = this.exportModel.type;

    let $iconWrapper = $root.find('.icon-wrap');
    let buttonText = `${EXPORT_MODEL[type].name} ${EXPORT_MODEL.downloadText}`;

    let buttonHtml = [];

    buttonHtml.push(`<button type="button" class="bx-txt-btn" title="${buttonText}">`);
    buttonHtml.push(`<span>${buttonText}</span>`);
    buttonHtml.push(`<i class="bw-icon i-25 i-ctrl-down"></i>`);
    buttonHtml.push('</button>');

    let $exportButton = $(buttonHtml.join(''));

    _addEventListenerForExportIconButton.call(this, $exportButton, type);

    $iconWrapper.append($exportButton);
}

/**
 * grid에 excel import 기능 추가
 *
 * @private
 */
function _addImportExcel() {

    if (_.isEmpty(this.importModel)) return;

    let $iconWrapper = this.$root.find('.icon-wrap');

    _addFileUploadButton.call(this, $iconWrapper);
}

/**
 * grid에 excel import 버튼을 추가한다
 *
 * @param {object} $iconWrapper - 생성 위치 타켓
 *
 * @private
 */
function _addFileUploadButton($iconWrapper = {}){

    let importModel = this.importModel;
    let type = importModel.type;
    let ajaxOption = this.importModel.ajaxOption;
    let url = ajaxOption.url;
    let enableImpButton = importModel.enableImpButton;

    let buttonText = `${IMPORT_MODEL[type].name} ${IMPORT_MODEL.uploadText}`;
    let html = [];

    let {$form: $form, $label:$importButton, $iframe:$iframe } = FORM.createFileUploadElements({
        'prefixId':'bxGrid',
        'action': url,
        'onFileChange': _sendExcelFile.bind(this)
    });

    if (UTIL.isIE9()) {
        $iconWrapper.append($form);
        $iconWrapper.append($iframe);
    }
    else {
        $iconWrapper.append($form.find('input'));
    }

    $iconWrapper.append($importButton);

    html.push(`<span>${buttonText}</span>`);
    html.push('<i class="bw-icon i-25 i-ctrl-up"></i>');

    $importButton.addClass('bx-txt-btn');
    $importButton.append($(html.join('')));

    if (!enableImpButton) $importButton.addClass('blind');
}

/**
 * 파일을 전송
 *
 * @param {object} e - 이벤트 객체
 *
 * @private
 */
function _sendExcelFile(e = {}){

    let $target = $(e.target);
    let ajaxOption = _getAjaxOption.call(this, AJAX_OPTION.IMPORT_OPTION);

    let $iconWrapper = this.$root.find('.icon-wrap');
    let $form = $iconWrapper.find('form');
    let $iframeElem = $iconWrapper.find('iframe');

    if (_.isUndefined(this.importModel)) CONSOLE.prop.throw(BxGrid, 'importModel', 'all');

    _.assign(ajaxOption.params, {'colModel': _getReverseColModel.call(this)});

    FORM.submit({
            "$formElem" : $form,
            "$iframeElem" : $iframeElem,
            "url": ajaxOption.url,
            "method": ajaxOption.method,
            "file": $target,
            "headers": ajaxOption.headers,
            "params": ajaxOption.params,
            "before": xhr => {
                ajaxOption.before.call(ajaxOption);
             },
            "success": data => {

                ajaxOption.success();

               _setDataForImportExcel.call(this,  data);
           },
            "error": ajaxOption.fail
        });

    FORM.clear($target);
}

/**
 * 서버로 부터 받은 data를 그리드에 바인딩
 *
 * @param {string} data - json 구조의 아이템
 *
 * @private
 */
function _setDataForImportExcel(data = null) {

	const importModel = this.importModel;
	const resModel = _getTransModel.call(this, AJAX_OPTION.IMPORT_OPTION).resModel;
    const enableResetData = importModel.enableResetData;
    
	if (_.isString(resModel) && resModel.length){
		data = _.get(data, resModel, data);
	}
	
    if (!_.isArray(data)){
        CONSOLE.prop.throw(BxGrid, ERR_MSG.notFoundItemViaResModel);
    }

    if (_isAjaxTransaction.call(this)){

        // 서버에 데이터를 재요청 한다.
        this.loadData();
    }
    else {

        let items = data;

        if (!enableResetData){
            items = _.concat(this.getAllRowData(), data);
        }

        this.resetGridData(items);
    }
}

/**
 * colModel 의 key 와 value 의 위치를 변경
 *
 * @private
 */
function _getReverseColModel() {

    let colModel = this[OPTS].colModel;
    let reverseCol = {};

    colModel.forEach((data, i) =>{

        if (data['hidden']) return;

        reverseCol[data['label']] = data['name'];
    });

    return JSON.stringify(reverseCol);
}

/**
 * export 아이콘에 클릭이벤트를 등록한다
 *
 * @param {object} $target = null - 타켓
 * @param {string} type = '' - 버튼 타입
 *
 * @private
 */
function _addEventListenerForExportIconButton($target = null, type = ''){

    switch(type){

        case 'excel': {

            $target.on('click', e => this.exportExcel.call(this));

            break;
        }
    }
}

/**
 * Time Stamp를 생성한다
 *
 * @returns {string} - 생성된 TimeStamp
 *
 * @private
 */
function _getTimeStamp(){

    let date = new Date();

    return UTIL.convertDateFormat(date.toString(), 'yyyyMMddhhmmss', true);
}

/**
 * export 파일을 생성 후 실행한다.
 *
 * @param {array} pageDatas - export 할 페이지 데이터 목록
 *
 * @private
 */
function _createExportFile(pageDatas = []){
	
	const exportModel = this.exportModel;
	const resModel = _getTransModel.call(this, AJAX_OPTION.EXPORT_OPTION).resModel;

	if (_.isString(resModel) && resModel.length){
		pageDatas = _.get(pageDatas, resModel, pageDatas);
	}

    if (!_.isArray(pageDatas)){
        CONSOLE.prop.throw(BxGrid, ERR_MSG.notFoundItemViaResModel);
    }

    let fileName = exportModel.fileName;
    let enableTimeStamp = exportModel.enableTimeStamp;
    let sheetName = exportModel.sheetName;

    let $exportTable = _getExportDOM.call(this, pageDatas);

    fileName = enableTimeStamp ? `${fileName}_${_getTimeStamp()}` : fileName;

    EXPORTER.exportExcel($exportTable, fileName, sheetName);
}

/**
 * export될 DOM을 가져온다
 *
 * @param {null|array|int} startIdx - 시작 페이지 번호
 * @param {int} endIdx - 마지막 페이지 번호
 * @param {object} pageDatas - 만들어질 row 데이터
 *
 * @returns {Object}
 *
 * @private
 */
function _getExportDOM(pageDatas = []){

    if (!pageDatas.length){
        CONSOLE.prop.throw(BxGrid, 'pageDatas', 'value');
    }

    let $header = $(this.$root.find('thead')[0].outerHTML);
    let footers = this.footers;

    let $wrap = $('<div></div>');
    let $table = $('<table></table>');

    let styleText = _createExportExcelStyle();
    let header = _extractHeaderDOM.call(this, $header);
    let rowDataHTML = _changePageDataToDOM.call(this, pageDatas);
    let footerHTML = _createFooterForExportDOM.call(this, footers, pageDatas);

    $table.append(header);
    $table.append(rowDataHTML);
    $table.append(footerHTML);

    $wrap.append(styleText);
    $wrap.append($table);

    return $wrap;
}

/**
 * export excel 파일의 style을 생성한다
 *
 * @returns {string}
 * @private
 */
function _createExportExcelStyle(){

    let style = [];

    style.push('<style type="text/css">');
    style.push('table th {');
    style.push('background-color: "#eee";');
    style.push('border: 1px solid;');
    style.push('}');
    style.push('</style>');

    return style.join('');
}

/**
 * export 될 header DOM으로 수정한다
 *
 * @param {object} $header - 생성된 jqgrid header 영역
 *
 * @returns {object} - 수정된 header 영역 *
 * @private
 */
function _extractHeaderDOM($header = null){

    // 첫번째 빈 tr 삭제
    $header.find('.jqg-first-row-header').remove();

    // caption 삭제
    $header.find('caption').remove();

    // checkbox 삭제
    $header.find('input').remove();

    // sort button 삭제
    $header.find('button').remove();

    // rownumber 헤더 삭제
    $header.find('.jqgh_rn').remove();

    // checkbox 헤더 삭제
    $header.find('.jqgh_cbox').remove();

    // inline 편집 헤더 삭제
    $header.find('th[id$="format"]').remove();

    // header resize 영역 삭제
    $header.find('span.ui-jqgrid-resize').remove();

    // display none 되어있는 th는 삭제
    _.map($header.find('th'), th => {

        let $th = $(th);

        if ($th.css('display') === 'none'){
            $th.remove();
        }
    });

    return $header.html();
}

/**
 * grid row 데이터를 가져온다
 *
 * @param {null|array|int} _startIdx - 시작 페이지 번호
 * @param {int|null} _endIdx - 마지막 페이지 번호
 *
 * @returns {Object[]} - grid row data
 *
 * @private
 */
function _extractPageData(_startIdx = null, _endIdx = null){

    let {startIdx, endIdx} = _validatePageIdx(_startIdx, _endIdx);

    let resultDatas = [];
    const mainDefer = $.Deferred();
    const resultPromiseFunc = (promises) => {

        $.when(...promises).done((...pageRowData) => {

            let pageDatas = _.union(...pageRowData) || [];

            return mainDefer.resolve(pageDatas);
        });
    };

    // 특정 페이지 데이터 가져오기
    if (_.isNull(startIdx)){
        resultDatas.push(this.getAllRowData());
    }
    else if (_.isArray(startIdx)){
        _.forEach(startIdx, idx => {
            resultDatas.push(this.getPageData(idx));
        });
    }
    else {
        for (let idx = startIdx; idx <= endIdx; idx++){
            resultDatas.push(this.getPageData(idx));
        }
    }

    // ajaxModel 사용 유무에 따른 처리방식 변경
    if (_isAjaxTransaction.call(this)){

        resultPromiseFunc(resultDatas);

        return mainDefer.promise();
    }
    else {
        return _.union(...resultDatas);
    }
}

/**
 * grid row 데이터를 가져온다
 *
 * @param {null|array|int} _startIdx - 시작 페이지 번호
 * @param {int|null} _endIdx - 마지막 페이지 번호
 *
 * @returns {Object[]} - grid row data
 *
 * @private
 */
function _validatePageIdx(startIdx = null, endIdx = null){

    if (!_.isNull(startIdx) && !_.isArray(startIdx)){

        startIdx = parseInt(startIdx, 10);

        if (isNaN(startIdx)){
            CONSOLE.prop.throw(BxGrid, 'startIdx', 'all');
        }
    }

    if (!_.isNull(endIdx)){

        endIdx = parseInt(endIdx, 10);

        if (isNaN(endIdx)){
            CONSOLE.prop.throw(BxGrid, 'endIdx', 'all');
        }
    }

    // 시작 페이지가 종료 페이지보다 크거나, endIdx가 null인 경우에 종료 페이지를 시작페이지와 동일하게 변경
    if (_.isNull(endIdx) || startIdx >= endIdx){
        endIdx = startIdx;
    }

    return {startIdx, endIdx};
}

/**
 * grid row 데이터를 DOM으로 변환한다
 *
 * @param {object[]} pageDatas - page row data
 *
 * @returns {string} 변환된 html
 *
 * @private
 */
function _changePageDataToDOM(pageDatas = []){

    const headerObj = _extractHeaderToColModel.call(this);
    const isFormatted = this.exportModel.dataFormat === EXPORT_MODEL.dataFormat.formatted ? true : false;

    let rowHtml = [];

    _.forEach(pageDatas, item => {

        rowHtml.push('<tr>');

        _.forEach(headerObj, headerItem => {

            let formatType = _getFormatStyle(headerItem.formatOption);
            let cellValue = item[headerItem.name];
            let id = item.id;

            if (isFormatted && !_.isUndefined(headerItem.formatOption) && headerItem.formatOption.type !== 'currency'){
                cellValue = _getFormatString.call(this, cellValue, headerItem.name, id);
            }

            rowHtml.push(`<td style='${formatType}'>${cellValue}</td>`);
        });

        rowHtml.push('</tr>');
    });

    return rowHtml.join('');
}

/**
 * 엑셀에 export 될 값의 style을 지정한다
 *
 * @param formatOption - format object
 *
 * @returns {string} excel format style
 *
 * @private
 */
function _getFormatStyle(formatOption = {}){

    let textType = 'mso-number-format:"\@"';
    let currencyType = 'text-align:right; mso-number-format:"\#\,0';

    let formatType = formatOption.type || '';
    let options = formatOption.options;

    if (!_.isPlainObject(formatOption)){
        return textType;
    }
    else if (formatType === FORMAT_TYPE.CURRENCY){

        if (!_.isUndefined(options.decimalPlaces) && options.decimalPlaces !== 0){

            currencyType += '.';

            for (let i = 0; i < options.decimalPlaces; i++){
                currencyType += '0';
            }
        }

        currencyType += '"';

        return currencyType;
    }
    else {
        return textType;
    }
}

/**
 * export 될 footer의 DOM을 생성한다
 *
 * @param {object} footers - footer 생성 option object
 * @param pageDatas - grid row datas
 *
 * @returns {string} 생성된 footer DOM
 *
 * @private
 */
function _createFooterForExportDOM(footers = {}, pageDatas = []){

    const singleCol = 1;

    let headerNameList = _extractHeaderToColModel.call(this);
    let trHTML = [];

    _.forEach(footers, tr => {

        let numberOfCol = singleCol;

        trHTML.push('<tr>');

        _.forEach(headerNameList, headerObj => {

            let tdHTML = '';

            if (numberOfCol === singleCol){

                let item = _.filter(tr, ['colName', headerObj.name]);

                if (item.length){

                    item = item[0];
                    tdHTML = _createTdHTML.call(this, item, pageDatas, headerObj.name);
                }

                if (item.numberOfCol > singleCol) numberOfCol = item.numberOfCol;
            }

            if (tdHTML.length){
                trHTML.push(tdHTML);
            }
            else if (numberOfCol > singleCol){
                numberOfCol--;
            }
            else {
                trHTML.push('<td></td>');
            }
        });

        trHTML.push('</tr>');
    });

    return trHTML.join('');
}

/**
 * footer의 td를 생성한다
 *
 * @param {object} item - 표현 될 footer object
 * @param {array} pageDatas - grid page row data
 * @param {string} cellName - header object
 *
 * @returns {string} td html
 *
 * @private
 */
function _createTdHTML(item = {}, pageDatas = [], cellName = ''){

    const REPLACE_CHAR = '{0}';

    let cellValue = item.type === 'label' ? item.content : _calcFooterValue(item.type, item.colName, pageDatas);

    cellValue = _getFormatString.call(this, cellValue, cellName);

    let replaceValue = item.content.replace(REPLACE_CHAR, cellValue);
    let colspanText = '';

    if (item.numberOfCol > 1) colspanText = `colspan='${item.numberOfCol}'`;

    return `<td ${colspanText}>${replaceValue}</td>`;
}

/**
 * 값을 포메팅 해준다
 *
 * @param {string} cellValue - 변환 할 값
 * @param {string} cellName - 변환 할 값의 헤더 이름
 * @param {string} rowId - rowId
 *
 * @returns {string} 변환된 값
 * @private
 */
function _getFormatString(cellValue = '', cellName = '', rowId = ''){

    let jqGrid = this.$container.get(0);
    let p = jqGrid.p;
    let colPos = p.iColByName[cellName];

    let resultString = cellValue;

    // jqgrid formatter를 이용해서 포매팅 관련
    // UTIL.getFormatString을 이용하여 커스텀 타입을 포매팅 하려면 customFormatter 의 arguments를 넣어줘야 포매팅이 가능하다.
    // 하지만 jqgrid에서 직접 만들어서 주는 arguments도 있어 해당 parameter는 생성해서 넣어줘야하나 매우 비효율적이라고 판단,
    // UTIL.getFormatString 대신 내장 jqgrid 함수로 포매팅하는 방법으로 변경
    resultString = jqGrid.formatter(rowId, cellValue, colPos, {[cellName]: cellValue}, "get");

    return resultString;
}

/**
 * colModel에서 Grid에 보여지는 header 정보를 순서대로 추출한다
 *
 * @returns {Array} 수집된 header 정보
 *
 * @private
 */
function _extractHeaderToColModel(){

    let headerObj = [];
    const colModel = this.getOPTS().colModel;

    _.forEach(colModel, item => {

        if ((_.isUndefined(item.hidden) || item.hidden === false) && item.name !== 'format'){
            headerObj.push({name: item.name, formatOption: item.formatOption});
        }
    });

    return headerObj;
}

/**
 * footer에 출력 될 값을 계산한다
 *
 * @param {string} type - footer 값을 계산할 타입
 * @param {string} colName - 검색 할 colName
 * @param {object[]} pageData - grid page row 데이터
 *
 * @returns {int} 계산된 값
 *
 * @private
 */
function _calcFooterValue(type = '', colName = '', pageData = []){

    let result = null;

    switch(type){

        case 'count' : {

            result = pageData.length;
            break;
        }
        case 'sum' : {

            result = 0;

            _.forEach(pageData, item => result += Number(item[colName]));

            break;
        }
        case 'avg' : {

            result = 0;

            _.forEach(pageData, item => result += Number(item[colName]));

            result /= pageData.length;

            break;
        }
        case 'min' : {

            _.forEach(pageData, item => {

                let compareValue = Number(item[colName]);

                if(_.isNull(result) || compareValue < result){
                    result = compareValue;
                }
            });

            break;
        }
        case 'max' : {

            _.forEach(pageData, item => {

                let compareValue = Number(item[colName]);

                if(_.isNull(result) || compareValue > result){
                    result = compareValue;
                }
            });

            break;
        }
    }

    return result;
}

/**
 * ajax 사용 여부를 반환한다.
 *
 * @returns {boolean} ajax 사용 여부
 *
 * @private
 */
function _isAjaxTransaction(){
    return this.ajaxModel.isAjaxTransaction;
}

/**
 * ajax option 초기화 함수
 *
 * @param {string} optionName - Ajax 통신때 사용할 옵션명
 *
 * @returns {object} - ajaxOption
 *
 * @private
 */
function _initAjaxOption(optionName = ''){

    let ajaxOption = _getAjaxOption.call(this, optionName);

	if (!_.isString(ajaxOption.url)){
        ajaxOption.url = '';
    }

	if (!_.isString(ajaxOption.method)){
        ajaxOption.method = 'post';
    }

    if (!_.isPlainObject(ajaxOption.headers)){
        ajaxOption.headers = {};
    }

    if (!_.isPlainObject(ajaxOption.params)){
        ajaxOption.params = {};
    }

    if (!_.isFunction(ajaxOption.before)){
        ajaxOption.before = function(){};
    }

    if (!_.isFunction(ajaxOption.success)){
        ajaxOption.success = function(){};
    }

    if (!_.isFunction(ajaxOption.fail)){
        ajaxOption.fail = function(){};
    }

    let ajaxModel = _getAjaxModel.call(this, optionName);

    if (optionName === AJAX_OPTION.IMPORT_OPTION){

        if (!_.isString(ajaxModel.resModel)){
            ajaxModel.resModel = DEFAULT_RES_MODEL;
        }
    }
    else if (optionName === AJAX_OPTION.EXPORT_OPTION){

        if (!_.isString(ajaxModel.resModel)){
            ajaxModel.resModel = DEFAULT_RES_MODEL;
        }
    }

    return ajaxOption;
}



module.exports = BxGrid;